table_by_retailer_categoria_ytd.template:
SELECT
  d.retailer,
  p.category                                                                                          AS categoria,
  SUM(CASE WHEN CAST(d.numeric_day / 100 AS INT) BETWEEN {ytd_start_ly_yyyymm} AND {ytd_end_ly_yyyymm}
           THEN d.ventas    END)                                                                      AS YTD_YA1_Valor,
  SUM(CASE WHEN CAST(d.numeric_day / 100 AS INT) BETWEEN {ytd_start_yyyymm}    AND {ytd_end_yyyymm}
           THEN d.ventas    END)                                                                      AS YTD_Valor,
  SUM(CASE WHEN CAST(d.numeric_day / 100 AS INT) BETWEEN {ytd_start_yyyymm}    AND {ytd_end_yyyymm}
           THEN d.ventas    END)
    / NULLIF(SUM(CASE WHEN CAST(d.numeric_day / 100 AS INT) BETWEEN {ytd_start_ly_yyyymm} AND {ytd_end_ly_yyyymm}
                      THEN d.ventas    END), 0)
    - 1                                                                                               AS YTD_vs_YA1_Valor,
  SUM(CASE WHEN CAST(d.numeric_day / 100 AS INT) BETWEEN {ytd_start_ly_yyyymm} AND {ytd_end_ly_yyyymm}
           THEN d.unidades  END)                                                                      AS YTD_YA1_Uni,
  SUM(CASE WHEN CAST(d.numeric_day / 100 AS INT) BETWEEN {ytd_start_yyyymm}    AND {ytd_end_yyyymm}
           THEN d.unidades  END)                                                                      AS YTD_Uni,
  SUM(CASE WHEN CAST(d.numeric_day / 100 AS INT) BETWEEN {ytd_start_yyyymm}    AND {ytd_end_yyyymm}
           THEN d.unidades  END)
    / NULLIF(SUM(CASE WHEN CAST(d.numeric_day / 100 AS INT) BETWEEN {ytd_start_ly_yyyymm} AND {ytd_end_ly_yyyymm}
                      THEN d.unidades  END), 0)
    - 1                                                                                               AS YTD_vs_YA1_Uni,
  SUM(CASE WHEN CAST(d.numeric_day / 100 AS INT) BETWEEN {ytd_start_ly_yyyymm} AND {ytd_end_ly_yyyymm}
           THEN d.unidades * CAST(p.Contenido_del_Empaque AS DOUBLE) END)                             AS YTD_YA1_Kg,
  SUM(CASE WHEN CAST(d.numeric_day / 100 AS INT) BETWEEN {ytd_start_yyyymm}    AND {ytd_end_yyyymm}
           THEN d.unidades * CAST(p.Contenido_del_Empaque AS DOUBLE) END)                             AS YTD_Kg,
  SUM(CASE WHEN CAST(d.numeric_day / 100 AS INT) BETWEEN {ytd_start_yyyymm}    AND {ytd_end_yyyymm}
           THEN d.unidades * CAST(p.Contenido_del_Empaque AS DOUBLE) END)
    / NULLIF(SUM(CASE WHEN CAST(d.numeric_day / 100 AS INT) BETWEEN {ytd_start_ly_yyyymm} AND {ytd_end_ly_yyyymm}
                      THEN d.unidades * CAST(p.Contenido_del_Empaque AS DOUBLE) END), 0)
    - 1                                                                                               AS YTD_vs_YA1_Kg
FROM prod_etl.gold.vima_dashboard_daily d
JOIN prod_etl.segmentation.products p ON d.id_product_retailer = p.id_product_retailer
JOIN prod_etl.segmentation.stores   s ON d.id_store = s.id_store
WHERE (
    CAST(d.numeric_day / 100 AS INT) BETWEEN {ytd_start_ly_yyyymm} AND {ytd_end_ly_yyyymm}
    OR CAST(d.numeric_day / 100 AS INT) BETWEEN {ytd_start_yyyymm}  AND {ytd_end_yyyymm}
  )
  AND s.store_channel != 'Cedis'
  AND p.category != 'OUT'
GROUP BY d.retailer, p.category
ORDER BY d.retailer, p.category

